    /**
     * List currently occupied cage numbers.
     * Used by: Admit form to show which cages are taken.
     */
    public List<String> findOccupiedCages() throws SQLException {
        String sql =
                "SELECT CageNumber FROM InpatientAdmissions " +
                        "WHERE  Status IN ('Admitted', 'Critical') " +
                        "AND    CageNumber IS NOT NULL";

        List<String> list = new ArrayList<>();
        try (Connection cn = DBConnection.getConnection();
             PreparedStatement ps = cn.prepareStatement(sql);
             ResultSet rs = ps.executeQuery()) {
            while (rs.next()) list.add(rs.getString("CageNumber"));
        }
        return list;
    }

    /**
     * Update status only. Valid: 'Admitted' | 'Critical' | 'Discharged'
     */
    public void updateStatus(int admissionID, String status) throws SQLException {
        String sql = "UPDATE InpatientAdmissions SET Status = ? WHERE AdmissionID = ?";
        try (Connection cn = DBConnection.getConnection();
             PreparedStatement ps = cn.prepareStatement(sql)) {
            ps.setString(1, status);
            ps.setInt(2, admissionID);
            ps.executeUpdate();
        }
    }

    /**
     * Set DischargeDate = today and Status = 'Discharged'.
     * Called by DischargeServlet.
     */
    public void discharge(int admissionID) throws SQLException {
        String sql =
                "UPDATE InpatientAdmissions " +
                        "SET    DischargeDate = CAST(GETDATE() AS date), Status = 'Discharged' " +
                        "WHERE  AdmissionID = ?";
        try (Connection cn = DBConnection.getConnection();
             PreparedStatement ps = cn.prepareStatement(sql)) {
            ps.setInt(1, admissionID);
            ps.executeUpdate();
        }
    }

    // ══════════════════════════════════════════════════════════════════════════
    // DailyAssessments
    // ══════════════════════════════════════════════════════════════════════════

    /**
     * Insert today's assessment.
     * Column: StaffID (updated schema — was VetID before)
     * @return generated AssessmentID
     */
    public int createAssessment(int admissionID, int staffID,
                                String condition, String treatmentToday) throws SQLException {
        String sql =
                "INSERT INTO DailyAssessments " +
                        "  (AdmissionID, StaffID, AssessmentDate, Condition, TreatmentToday) " +
                        "VALUES (?, ?, CAST(GETDATE() AS date), ?, ?)";

        try (Connection cn = DBConnection.getConnection();
             PreparedStatement ps = cn.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS)) {
            ps.setInt(1, admissionID);
            ps.setInt(2, staffID);
            ps.setString(3, condition);
            ps.setString(4, treatmentToday);
            ps.executeUpdate();
            try (ResultSet keys = ps.getGeneratedKeys()) {
                return keys.next() ? keys.getInt(1) : -1;
            }
        }
    }

    /**
     * All assessments for one admission, newest first.
     * JOIN Staff on StaffID (updated schema).
     */
    public List<DailyAssessment> findAssessmentsByAdmission(int admissionID) throws SQLException {
        String sql =
                "SELECT da.AssessmentID, da.AdmissionID, da.StaffID, " +
                        "       da.AssessmentDate, da.Condition, da.TreatmentToday, " +
                        "       s.FullName AS VetName " +
                        "FROM   DailyAssessments da " +
                        "JOIN   Staff s ON s.StaffID = da.StaffID " +
                        "WHERE  da.AdmissionID = ? " +
                        "ORDER  BY da.AssessmentDate DESC";

        List<DailyAssessment> list = new ArrayList<>();
        try (Connection cn = DBConnection.getConnection();
             PreparedStatement ps = cn.prepareStatement(sql)) {
            ps.setInt(1, admissionID);
            try (ResultSet rs = ps.executeQuery()) {
                while (rs.next()) list.add(mapAssessment(rs));
            }
        }
        return list;
    }

    /**
     * Returns true if an assessment for today already exists for this admission.
     * Prevents duplicate daily entries.
     */
    public boolean hasTodayAssessment(int admissionID) throws SQLException {
        String sql =
                "SELECT 1 FROM DailyAssessments " +
                        "WHERE  AdmissionID   = ? " +
                        "AND    AssessmentDate = CAST(GETDATE() AS date)";
        try (Connection cn = DBConnection.getConnection();
             PreparedStatement ps = cn.prepareStatement(sql)) {
            ps.setInt(1, admissionID);
            try (ResultSet rs = ps.executeQuery()) {
                return rs.next();
            }
        }
    }

    // ══════════════════════════════════════════════════════════════════════════
    // Helpers
    // ══════════════════════════════════════════════════════════════════════════

    private List<InpatientAdmission> query(String sql) throws SQLException {
        List<InpatientAdmission> list = new ArrayList<>();
        try (Connection cn = DBConnection.getConnection();
             PreparedStatement ps = cn.prepareStatement(sql);
             ResultSet rs = ps.executeQuery()) {
            while (rs.next()) list.add(mapAdmission(rs));
        }
        return list;
    }

    private InpatientAdmission mapAdmission(ResultSet rs) throws SQLException {
        InpatientAdmission a = new InpatientAdmission();
        a.setAdmissionID(rs.getInt("AdmissionID"));

        // RecordID is nullable
        Integer recordID = rs.getObject("RecordID", Integer.class);
        a.setRecordID(recordID);

        a.setPetID(rs.getInt("PetID"));
        a.setStatus(rs.getString("Status"));
        a.setCageNumber(rs.getString("CageNumber"));

        // CageID is nullable
        Integer cageID = rs.getObject("CageID", Integer.class);
        a.setCageID(cageID);

        Date admit = rs.getDate("AdmitDate");
        if (admit != null) a.setAdmitDate(admit.toLocalDate());

        Date discharge = rs.getDate("DischargeDate");
        if (discharge != null) a.setDischargeDate(discharge.toLocalDate());

        // joined
        a.setPetName(rs.getString("PetName"));
        a.setOwnerName(rs.getString("OwnerName"));
        a.setOwnerEmail(rs.getString("OwnerEmail"));
        a.setCustomerID(rs.getInt("CustomerID"));
        a.setAppointmentID(rs.getInt("AppointmentID"));
        return a;
    }

    private DailyAssessment mapAssessment(ResultSet rs) throws SQLException {
        DailyAssessment d = new DailyAssessment();
        d.setAssessmentID(rs.getInt("AssessmentID"));
        d.setAdmissionID(rs.getInt("AdmissionID"));
        d.setVetID(rs.getInt("StaffID"));   // column renamed StaffID in new schema
        d.setCondition(rs.getString("Condition"));
        d.setTreatmentToday(rs.getString("TreatmentToday"));
        d.setVetName(rs.getString("VetName"));

        Date date = rs.getDate("AssessmentDate");
        if (date != null) d.setAssessmentDate(date.toLocalDate());
        return d;
    }
}

package com.petclinic.service;

import com.petclinic.dao.InpatientAdmissionDAO;
import com.petclinic.dao.InvoiceDAO;
import com.petclinic.dao.NotificationDAO;
import com.petclinic.model.DailyAssessment;
import com.petclinic.model.InpatientAdmission;

import java.sql.SQLException;
import java.time.LocalDate;
import java.time.temporal.ChronoUnit;
import java.util.List;

/**
 * Business logic for BP-04: Inpatient.
 * Servlets call this class only — never touch DAO directly from servlet.
 */
public class InpatientService {

    private static final double DAILY_RATE = 200_000.0; // VND per day

    private final InpatientAdmissionDAO dao      = new InpatientAdmissionDAO();
    private final InvoiceDAO            invoiceDAO = new InvoiceDAO();
    private final NotificationDAO       notifDAO  = new NotificationDAO();

    // ── Receptionist ──────────────────────────────────────────────────────────

    /**
     * Admit a pet:
     *   1. Validate cage not already occupied
     *   2. Create InpatientAdmissions row
     * @return new admissionID
     */
    public int admitPet(int recordID, int petID, String cageNumber)
            throws SQLException {
        List<String> occupied = dao.findOccupiedCages();
        if (occupied.contains(cageNumber.trim())) {
            throw new IllegalStateException(
                    "Cage " + cageNumber + " is already occupied.");
        }
        return dao.create(recordID, petID, cageNumber.trim());
    }

    /**
     * Discharge a pet:
     *   1. Set DischargeDate = today, Status = Discharged
     *   2. Calculate fee = DAILY_RATE × days stayed (min 1)
     *   3. Create Invoice (Unpaid)
     *   4. Notify customer
     * @return new invoiceID
     */
    public int dischargePet(int admissionID) throws SQLException {
        InpatientAdmission a = dao.findById(admissionID);
        if (a == null)
            throw new IllegalArgumentException("Admission not found: " + admissionID);

        // 1. mark discharged
        dao.discharge(admissionID);

        // 2. fee calculation
        LocalDate admitDate = a.getAdmitDate() != null
                ? a.getAdmitDate() : LocalDate.now();
        long days = Math.max(1, ChronoUnit.DAYS.between(admitDate, LocalDate.now()));
        double total = DAILY_RATE * days;

        // 3. create invoice
        int invoiceID = invoiceDAO.create(
                a.getAppointmentID(),
                a.getCustomerID(),
                total,
                "Unpaid"
        );

        // 4. notify owner
        notifDAO.createForCustomer(
                a.getCustomerID(),
                "Your pet " + a.getPetName() + " has been discharged",
                "Stay duration: " + days + " day(s). "
                        + "Total fee: " + String.format("%,.0f", total) + " VND. "
                        + "Please proceed to payment."
        );

        return invoiceID;
    }

    public List<InpatientAdmission> getActiveAdmissions() throws SQLException {
        return dao.findAllActive();
    }

    public List<InpatientAdmission> getAdmissionsForCustomer(int customerID)
            throws SQLException {
        return dao.findByCustomer(customerID);
    }

    public InpatientAdmission getAdmission(int admissionID) throws SQLException {
        return dao.findById(admissionID);
    }

    public List<String> getOccupiedCages() throws SQLException {
        return dao.findOccupiedCages();
    }

    // ── Veterinarian ──────────────────────────────────────────────────────────

    /**
     * Save daily assessment.
     * Uses StaffID (updated schema — column was VetID before).
     */
    public void saveDailyAssessment(int admissionID, int staffID,
                                    String condition, String treatment)
            throws SQLException {
        if (dao.hasTodayAssessment(admissionID)) {
            throw new IllegalStateException(
                    "Today's assessment has already been submitted for this admission.");
        }
        dao.createAssessment(admissionID, staffID,
                condition  != null ? condition.trim()  : "",
                treatment  != null ? treatment.trim()  : "");

        // notify owner
        InpatientAdmission a = dao.findById(admissionID);
        if (a != null) {
            notifDAO.createForCustomer(
                    a.getCustomerID(),
                    "Daily update for " + a.getPetName(),
                    "Today's condition: " + condition
            );
        }
    }

    /**
     * Mark pet as Critical — triggers urgent notification to owner.
     */
    public void markCritical(int admissionID) throws SQLException {
        dao.updateStatus(admissionID, "Critical");
        InpatientAdmission a = dao.findById(admissionID);
        if (a != null) {
            notifDAO.createForCustomer(
                    a.getCustomerID(),
                    "⚠️ URGENT: " + a.getPetName() + " is in Critical Condition",
                    "Please contact the clinic immediately."
            );
        }
    }

    public List<DailyAssessment> getAssessments(int admissionID)
            throws SQLException {
        return dao.findAssessmentsByAdmission(admissionID);
    }

    public boolean hasTodayAssessment(int admissionID) throws SQLException {
        return dao.hasTodayAssessment(admissionID);
    }
}

package com.petclinic.service;

import com.petclinic.dao.InpatientAdmissionDAO;
import com.petclinic.dao.InvoiceDAO;
